mapper.select:
/* UsimPrdtMngMapper.usimPrdtMngList */ SELECT RPRS_PRDT_ID , PRDT_CODE , PRDT_NM , PRDT_DESC , OUT_UNIT_PRIC , USE_YN , UNIT_PRIC_APPL_DTTM , UNIT_PRIC_EXPR_DTTM , IMG_FILE , (SELECT FILE_NM /* 파일명 */ FROM ORG_FILE_MGMT_MST OFMM WHERE OFMM.ATT_SCTN = 'M2M' AND OFMM.ORGN_ID = A.RPRS_PRDT_ID) AS ORG_IMG_FILE , FN_GET_USRNM(A.RVISN_ID) AS USR_NM FROM MSP_M2M_MDL A WHERE 1=1
AND A.RPRS_PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR}
AND A.PRDT_CODE = #{prdtCode, jdbcType=VARCHAR}
AND A.PRDT_NM LIKE '%' || #{prdtNm, jdbcType=VARCHAR} || '%'
AND A.USE_YN = #{useYn, jdbcType=VARCHAR}
ORDER BY A.RPRS_PRDT_ID, A.PRDT_CODE, A.PRDT_NM

/* UsimPrdtMngMapper.usimPrdtMngHist */ SELECT RPRS_PRDT_ID , PRDT_CODE , PRDT_NM , PRDT_DESC , OUT_UNIT_PRIC , OUT_UNIT_PRIC * 1.1 OUT_UNIT_PRIC_VAT , USE_YN , UNIT_PRIC_APPL_DTTM , UNIT_PRIC_EXPR_DTTM , IMG_FILE , ORG_IMG_FILE , FN_GET_USRNM(A.RVISN_ID) AS USR_NM , TO_CHAR(RVISN_DTTM,'YYYY-MM-DD HH24:MI:SS') RVISN_DTTM FROM MSP_M2M_MDL_HIST A WHERE 1=1
AND A.RPRS_PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR}
ORDER BY A.SEQ_NUM DESC

