  , #{prdtDesc, jdbcType=VARCHAR}
  , #{outUnitPric, jdbcType=VARCHAR}
  , #{useYn, jdbcType=VARCHAR}
  , #{unitPricApplDttm, jdbcType=VARCHAR}
  , #{unitPricExprDttm, jdbcType=VARCHAR}
  , #{imgFile, jdbcType=VARCHAR}
  , #{orgImgFile, jdbcType=VARCHAR}
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
)

mapper.update:
/* UsimPrdtMngMapper.usimPrdtUpdate */
UPDATE  MSP_M2M_MDL
   SET  PRDT_CODE = #{prdtCode, jdbcType=VARCHAR}
      , PRDT_NM = #{prdtNm, jdbcType=VARCHAR}
      , PRDT_DESC = #{prdtDesc, jdbcType=VARCHAR}
      , OUT_UNIT_PRIC = #{outUnitPric, jdbcType=VARCHAR}
      , USE_YN = #{useYn, jdbcType=VARCHAR}
      , UNIT_PRIC_APPL_DTTM = #{unitPricApplDttm, jdbcType=VARCHAR}
      , UNIT_PRIC_EXPR_DTTM = #{unitPricExprDttm, jdbcType=VARCHAR}
      , IMG_FILE = #{imgFile, jdbcType=VARCHAR}
      , ORG_IMG_FILE = #{orgImgFile, jdbcType=VARCHAR}
      , RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
      , RVISN_DTTM = SYSDATE
 WHERE  RPRS_PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR}

